const express = require('express');
const cors = require('cors');
const jwt = require('jsonwebtoken');
const { MagicBell } = require('magicbell-js');
require('dotenv').config();

const app = express();
app.use(cors());

const port = 3001;

const runId = process.env.ZEALT_RUN_ID || 'default-run-id';
const magicbellEmail = process.env.MAGICBELL_EMAIL || 'test';
const userEmail = `${magicbellEmail}+${runId}@gmail.com`;
const userExternalId = `user-${runId}`;

const magicbellApiKey = process.env.MAGICBELL_API_KEY || 'default-api-key';
const magicbellApiSecret = process.env.MAGICBELL_API_SECRET || 'default-secret-key';

const magicbell = new MagicBell({
  apiKey: magicbellApiKey,
  apiSecret: magicbellApiSecret,
});

async function bootstrap() {
  try {
    // Upsert the user
    await magicbell.users.create({
      external_id: userExternalId,
      email: userEmail,
      first_name: `User ${runId}`,
    });

    // Send a seed broadcast
    await magicbell.broadcasts.create({
      broadcast: {
        title: `Welcome to MagicBell ${runId}`,
        recipients: [{ external_id: userExternalId }],
      }
    });

    console.log('Bootstrap completed successfully.');
  } catch (error) {
    console.error('Error during bootstrap:', error);
  }
}

app.get('/token', (req, res) => {
  const payload = {
    user_external_id: userExternalId,
    user_email: userEmail,
    api_key: magicbellApiKey,
  };

  const token = jwt.sign(payload, magicbellApiSecret, {
    algorithm: 'HS256',
    expiresIn: '1h',
  });

  res.json({ token });
});

app.listen(port, () => {
  console.log(`Backend listening at http://localhost:${port}`);
  bootstrap();
});

import { useEffect, useState } from 'react';
import Provider from '@magicbell/react/context-provider';
import FloatingInbox from '@magicbell/react/floating-inbox';

function App() {
  const [token, setToken] = useState(null);

  useEffect(() => {
    fetch('http://localhost:3001/token')
      .then((res) => res.json())
      .then((data) => {
        setToken(data.token);
      })
      .catch((err) => {
        console.error('Failed to fetch token:', err);
      });
  }, []);

  if (!token) {
    return <div>Loading MagicBell...</div>;
  }

  return (
    <Provider token={token}>
      <div style={{ padding: '20px' }}>
        <h1>MagicBell Custom Theme Inbox</h1>
        <FloatingInbox 
          placement="bottom-end"
          height={600}
          width={500}
          offset={20}
        />
      </div>
    </Provider>
  );
}

export default App;

