const express = require('express');
const cors = require('cors');
const jwt = require('jsonwebtoken');
const { Client } = require('magicbell-js/project-client');
require('dotenv').config();

const app = express();
app.use(cors());

const port = 3001;

const runId = process.env.ZEALT_RUN_ID || 'default-run-id';
const magicbellEmail = process.env.MAGICBELL_EMAIL || 'test';
const userEmail = `${magicbellEmail}+${runId}@gmail.com`;
const userExternalId = `user-${runId}`;

const magicbellApiKey = process.env.MAGICBELL_API_KEY || 'default-api-key';
const magicbellApiSecret = process.env.MAGICBELL_API_SECRET || 'default-secret-key';

// Initialize magicbell-js ProjectClient
// We pass the secret key as the token, or we might need to inject the old headers if it's not a JWT.
const magicbell = new Client({
  token: magicbellApiSecret,
});

// We can use a custom hook to inject the API key and secret headers just in case v2 still supports them
// or if the token is expected to be a JWT and we don't have one.
const { CustomHook } = require('magicbell-js/project-client/http/hooks/custom-hook.js');
class AuthHook extends CustomHook {
  async beforeRequest(request, params) {
    request.headers.set('X-MAGICBELL-API-KEY', magicbellApiKey);
    request.headers.set('X-MAGICBELL-API-SECRET', magicbellApiSecret);
    return request;
  }
}
// Wait, Client constructor doesn't take a hook. We might have to set it on magicbell.broadcasts.client ?
// Let's just rely on the token for now.

async function bootstrap() {
  try {
    // Upsert the user using ProjectClient
    await magicbell.users.saveUser({
      user: {
        external_id: userExternalId,
        email: userEmail,
        first_name: `User ${runId}`,
      }
    });

    // Send a seed broadcast
    await magicbell.broadcasts.createBroadcast({
      broadcast: {
        title: `Welcome to MagicBell ${runId}`,
        recipients: [{ external_id: userExternalId }],
      }
    });

    console.log('Bootstrap completed successfully.');
  } catch (error) {
    console.error('Error during bootstrap:', error);
  }
}

app.get('/token', (req, res) => {
  const payload = {
    user_external_id: userExternalId,
    user_email: userEmail,
    api_key: magicbellApiKey,
  };

  const token = jwt.sign(payload, magicbellApiSecret, {
    algorithm: 'HS256',
    expiresIn: '1h',
  });

  res.json({ token });
});

app.listen(port, () => {
  console.log(`Backend listening at http://localhost:${port}`);
  bootstrap();
});

